if (inputValue == null) return null;
const raw = String(inputValue).trim();
if (!raw) return null;
if (/^\d{4}-\d{2}-\d{2}$/.test(raw)) return raw;

const match = raw.match(/^([A-Za-z]+)\s+(\d{1,2})(?:st|nd|rd|th)?(?:,\s*(\d{4}))?$/);
if (!match) return raw;

const months = {
  january: "01",
  february: "02",
  march: "03",
  april: "04",
  may: "05",
  june: "06",
  july: "07",
  august: "08",
  september: "09",
  october: "10",
  november: "11",
  december: "12"
};

const month = months[match[1].toLowerCase()];
if (!month) return raw;

const day = String(parseInt(match[2], 10)).padStart(2, "0");
const year = match[3] || String(new Date().getFullYear());
return `${year}-${month}-${day}`;
